-- Poems batch 370
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('87b046eb-3858-437f-bd60-98a731b7b20f','龜溪左顧亭二首  其一','劉一止','宋','宋诗','song-poetry','','[]','餘不溪上山，映我杯中綠。',24,'全唐诗/poet.song.84000.json','["餘不溪上山，映我杯中綠。", "我醉狂欲歌，潛蛟睡方熟。"]'),
('097fa060-1d9a-4107-b7b3-a1e75d81dc88','龜溪左顧亭二首  其二','劉一止','宋','宋诗','song-poetry','','[]','溪面寒無風，澄瑩千丈綠。',24,'全唐诗/poet.song.84000.json','["溪面寒無風，澄瑩千丈綠。", "我欲放輕舠，霜鏡不可觸。"]'),
('c03d69e8-1d86-4be3-8a47-0e247c620f4f','次韻虞仲容詠雪一首','劉一止','宋','宋诗','song-poetry','','[]','十年九作窮途客，慣見天花面旋飄。',64,'全唐诗/poet.song.84000.json','["十年九作窮途客，慣見天花面旋飄。", "江上舞鷗如背我，沙邊立鶴獨齊腰。", "衣黏落片行呼酒，船觸輕冰半渡橋。", "誰識此時詩思亂，緩歌黄竹想西瑤。"]'),
('9e50a698-06ec-4dc6-9ba0-8608e7d7767a','宿揚子江口一首','劉一止','宋','宋诗','song-poetry','','[]','客橋沙觜渺縱横，二紀風烟老此行。',64,'全唐诗/poet.song.84000.json','["客橋沙觜渺縱横，二紀風烟老此行。", "待得江頭明月出，恰當船底暗潮生。", "旅人夢冷無留想，別浦帆歸有呼聲。", "斷念此生惟付酒，爲誰驚走撰瓶罌。"]'),
('4005c141-373b-447b-a770-e1d2e732f8ad','次韻朱賓老删定月夜相訪一首','劉一止','宋','宋诗','song-poetry','','[]','一水相望十里餘，扁舟夜載月明俱。',64,'全唐诗/poet.song.84000.json','["一水相望十里餘，扁舟夜載月明俱。", "君今身爲故人出，我亦年來此客無。", "夜久燈孤疑是夢，樽空僕卧不成呼。", "殘年會見干戈息，共買嵌巖著老軀。"]'),
('3474e57d-160c-4dd1-8e85-2b4df381fe0b','次韻宋希仲侍郎見貽一首','劉一止','宋','宋诗','song-poetry','','[]','今古宦遊長作客，每逢佳處欲忘年。',64,'全唐诗/poet.song.84000.json','["今古宦遊長作客，每逢佳處欲忘年。", "頗将幻境觀塵世，始信臞儒是列仙。", "野邑分橋山带色，晚雲藏寺水黏天。", "公身未属烟波管，莫向津頭買釣船。"]'),
('1aaa9587-5746-46ea-97b8-6f65421371e4','睡足齋一首','劉一止','宋','宋诗','song-poetry','','[]','此地誰令著此翁，角巾欹倒鬢如蓬。',64,'全唐诗/poet.song.84000.json','["此地誰令著此翁，角巾欹倒鬢如蓬。", "興高絕壁松聲外，夢破寒花雀啅中。", "睡債幾時償賽足，書淫前日洗除空。", "故人若問安心法，一酌村酤薦晚菘。"]'),
('5a470262-b39c-4e1a-a7b9-67621fedba64','摘星嶺一首','劉一止','宋','宋诗','song-poetry','','[]','籋磴緣梯興未窮，青冥有路欲乘風。',64,'全唐诗/poet.song.84000.json','["籋磴緣梯興未窮，青冥有路欲乘風。", "朝雲暮雨在脚下，井鉞參旗落手中。", "比世此身長作客，半癡半黠忽成翁。", "枕抛偃蹇巔崕上，一洗平生眼界空。"]'),
('ecf44199-add5-4e9a-b8dd-6ed59498d3ca','次韻鄭維心詠梅一首','劉一止','宋','宋诗','song-poetry','','[]','山路雪消梅半吐，隔林光已見疏明。',64,'全唐诗/poet.song.84000.json','["山路雪消梅半吐，隔林光已見疏明。", "凍醪似蜜從誰賞，斲句如冰得我驚。", "卧樹照溪春思净，細香留客暮寒清。", "胡塵未遠邊風急，十載花前笑不成。"]'),
('184e1dd3-4749-41cc-ad40-f286716f9302','次韻林少瞻遊禹廟一首','劉一止','宋','宋诗','song-poetry','','[]','客裏杯觴不易逢，越王宮好莫匆匆。',64,'全唐诗/poet.song.84000.json','["客裏杯觴不易逢，越王宮好莫匆匆。", "春容雨打風吹後，山色朝來暮去中。", "京國昔從秋序別，齋廚猶憶飯時同。", "清時更作他年約，七塔三山夢已通。"]'),
('3ba114cc-918f-4479-b022-ac4ef3f2d7d0','元日得雪三日立春','劉一止','宋','宋诗','song-poetry','','[]','斗柄御山曉直寅，夜聞笳鼓又迎春。',64,'全唐诗/poet.song.84000.json','["斗柄御山曉直寅，夜聞笳鼓又迎春。", "尚欣窮臘酬三白，更薦嘉蔬繼五辛。", "鳩杖多情扶我老，琪花有意爲誰新。", "甲兵不用銀河洗，始覺今年一笑真。"]'),
('5cbaf6c4-e267-4172-ab45-dfc53d4858a6','比過石壁訪王元渤舍人欲觀棋戰聞同魚軒出遊獨與戎琳二師對語久之明日元渤有詩見貽次韻奉酬','劉一止','宋','宋诗','song-poetry','','[]','緩緩遊春且莫催，而今揮麈短轅回。',64,'全唐诗/poet.song.84000.json','["緩緩遊春且莫催，而今揮麈短轅回。", "一百五日天氣近，二十四番花信來。", "賭墅未容窺謝傅，即心聊復探黄梅。", "歸來索共梅花笑，老眼如何得暫開。"]'),
('19ec0499-af49-429c-8134-1bac23b14751','次韻奉酬元渤見過奕棋小飲及觀館閣題名之作','劉一止','宋','宋诗','song-poetry','','[]','珠玉當年咳唾成，元劉何自敢齊名。',64,'全唐诗/poet.song.84000.json','["珠玉當年咳唾成，元劉何自敢齊名。", "夢回雲海西崑逮，春到江村北渚明。", "誰爲少陵償酒債，更憐侯喜得詩聲。", "杯中賢聖君休問，局上光陰我獨驚。"]'),
('fe5647ab-964f-453f-8979-763ae8bf0eb9','方欲相約爲孔侯溪上之遊忽辱佳篇復次元韻','劉一止','宋','宋诗','song-poetry','','[]','山色溪烟淡墨成，隔溪幽鳥自呼名。',64,'全唐诗/poet.song.84000.json','["山色溪烟淡墨成，隔溪幽鳥自呼名。", "未妨濁酒陪心賞，更借清詩作眼明。", "桃葉不關今夕恨，松枝猶是古時聲。", "扁舟醉後從漂兀，個處應無寵辱驚。"]'),
('4a0ce0c3-d815-4098-8124-1f7c21230c49','次韻周秀實監丞嘉仲府判叔姪貽王元渤舍人二首詩中見反且恨不與奕棋之會  其一','劉一止','宋','宋诗','song-poetry','','[]','不踏清門曉鼓朝，山林真樂在朋曹。',64,'全唐诗/poet.song.84000.json','["不踏清門曉鼓朝，山林真樂在朋曹。", "烏衣賢胄風流遠，赤壁諸郎氣義高。", "底事裁詩多態度，也應索酒甚粗豪。", "殘年我獨棋中影，從此天刑儻遂逃。"]'),
('427e04d2-1ae7-4de3-af29-8140a6ffe3ee','次韻周秀實監丞嘉仲府判叔姪貽王元渤舍人二首詩中見反且恨不與奕棋之會  其二','劉一止','宋','宋诗','song-poetry','','[]','人言我老是頑仙，坐隱紋枰不計年。',64,'全唐诗/poet.song.84000.json','["人言我老是頑仙，坐隱紋枰不計年。", "何用山廛分小大，直将壺嶠比方圓。", "爭雄未羡七擒略，見事常輸一着先。", "好覓周郎雲水外，紅渠千頃藕如船。"]'),
('f350fe78-2f00-4521-ab7d-fc9acd9eb5da','次韻鄭維心見貽一首','劉一止','宋','宋诗','song-poetry','','[]','身病何因到赤墀，眼昏不復下書帷。',64,'全唐诗/poet.song.84000.json','["身病何因到赤墀，眼昏不復下書帷。", "杯觴有限長羞澀，故舊無多足別離。", "對白抽黄餘習氣，看朱成碧記當時。", "江村投老俱牢落，猶喜詩情似拾遺。"]'),
('bec71be0-3998-42d0-890a-8c633aa3af14','維心以僕假守毘陵與嘉禾南徐弟姪分符接壤作詩見貽次韻一首','劉一止','宋','宋诗','song-poetry','','[]','家風五字作長城，四至何曾慕九卿。',64,'全唐诗/poet.song.84000.json','["家風五字作長城，四至何曾慕九卿。", "問舍山林端欲老，分符湖海尚叨榮。", "北南二阮俱貧士，大小兩馮慚頌聲。", "獨羡書成鄭夫子，會令千載意分明。"]'),
('f6851eab-ebe4-49be-8899-7c892b794ff7','次韻萬廷老見貽一首','劉一止','宋','宋诗','song-poetry','','[]','梅花村上駐歸帆，知有幽人住此菴。',64,'全唐诗/poet.song.84000.json','["梅花村上駐歸帆，知有幽人住此菴。", "誰遺疏香随舵尾，故憐春色在枝南。", "溪前水落沙痕出，門外山横雪意酣。", "詩似何郎情不淺，更留佳處後來談。"]'),
('83488f07-eb99-478d-acb8-929d88f7e1b2','次韻王柱史題密印師竂一首','劉一止','宋','宋诗','song-poetry','','[]','巖下風輕進竹凉，道人身共翠梢長。',64,'全唐诗/poet.song.84000.json','["巖下風輕進竹凉，道人身共翠梢長。", "饑腸欲和春泉響，鼻觀先參煮菜香。", "何處人間有癡黠，不将身外較閑忙。", "鄰家柱史哦詩夜，未厭敲門月到墻。"]'),
('63bb3a85-3ea1-42c9-a1d6-cff2ad08d8c0','留題呂宣義知命小園一首','劉一止','宋','宋诗','song-poetry','','[]','雖無萬竹等封侯，半畝清陰趣自幽。',64,'全唐诗/poet.song.84000.json','["雖無萬竹等封侯，半畝清陰趣自幽。", "菘韮尚能供早晚，菊蘭聊欲記春秋。", "歸來久已同彭澤，休去寧須問石頭。", "短褐飄零嗟我老，他年未往亦風流。"]'),
('4dee5087-f0e3-42b8-ae54-c89c865818a3','登學宮城墻眺望寄曾宏父','劉一止','宋','宋诗','song-poetry','','[]','寂寞無氈老鄭虔，登臨此日意茫然。',64,'全唐诗/poet.song.84000.json','["寂寞無氈老鄭虔，登臨此日意茫然。", "雲開北渚炊烟外，春到西城戰血邊。", "江草喚愁無畔岸，官梅動興得清便。", "南風藻思傳家舊，好寄東風御柳篇。"]'),
('21e7c31f-45aa-4598-bb45-12cd0da6233c','同諸曹泛舟城南曾守餉酒示詩次其韻','劉一止','宋','宋诗','song-poetry','','[]','十年溪渚夢經行，更借風烟作眼明。',64,'全唐诗/poet.song.84000.json','["十年溪渚夢經行，更借風烟作眼明。", "官身擬赴鷗鷺約，小敵忽逢詩酒勍。", "今者不樂愧幽子，日後欲醉無麴生。", "五馬會尋芳草路，肯教綠葉便陰成。"]'),
('543fd7ce-35a4-48c7-8d13-1a70a5f80ab6','題章右推砥齋一首','劉一止','宋','宋诗','song-poetry','','[]','今古時清罰自清，由來讞獄賴儒生。',64,'全唐诗/poet.song.84000.json','["今古時清罰自清，由來讞獄賴儒生。", "将軍誤怪獄吏貴，廷尉今稱天下平。", "萬態詎容逃水鏡，此心真欲似權衡。", "公家世德高門閥，更看陰功踵令名。"]'),
('2a33660d-45df-4c7c-9815-03e8ac2af305','題道場山一首','劉一止','宋','宋诗','song-poetry','','[]','雲亂修堂冰不如，妙香随處滿空虚。',64,'全唐诗/poet.song.84000.json','["雲亂修堂冰不如，妙香随處滿空虚。", "頭陀浩劫衣塵在，回向此生心地初。", "涉世情疏終簡懶，愛山緣重費消除。", "道人勸我深發省，相對五更聽粥魚。"]'),
('5a9a14a8-f137-4cc7-ba51-4fca7102ef05','莫師文以訪弟調官巴川用周子醇韻作詩贈行','劉一止','宋','宋诗','song-poetry','','[]','三刀昔夢劍東州，援筆今看峽倒流。',64,'全唐诗/poet.song.84000.json','["三刀昔夢劍東州，援筆今看峽倒流。", "晚歲拾遺長憶弟，異鄉王粲忍登樓。", "微官等是身懸寄，平世何曾道阻修。", "他日歸飛兩黄鵠，伴儂苕渚共賡酬。"]'),
('21b23aaa-172a-4ef3-afa1-74a47b3c7126','次韻邵子非見貽一首','劉一止','宋','宋诗','song-poetry','','[]','夢想風神不記春，相逢欲看夢中因。',64,'全唐诗/poet.song.84000.json','["夢想風神不記春，相逢欲看夢中因。", "安知晚歲歸吳客，却見當時入洛人。", "賦似文園真有氣，詩非子建諒誰親。", "會須剪燭西窗語，莫怪長頭酒事頻。"]'),
('29a03090-21fd-4811-8072-34a37f0f4948','從子非登月波樓戲用前韻并簡何子楚','劉一止','宋','宋诗','song-poetry','','[]','洗醆初嘗麴米春，一樽相屬是前因。',64,'全唐诗/poet.song.84000.json','["洗醆初嘗麴米春，一樽相屬是前因。", "忽驚萬頃月波上，相對九霄風露人。", "十載京塵如夢破，半生鷗鳥已心親。", "他時喚取何郎到，要遣官梅動興頻。"]'),
('1eb1ec29-359e-402d-ac65-b280c64afedf','寄燕山帥幕家姪季高一首','劉一止','宋','宋诗','song-poetry','','[]','疇昔江湖自在身，而今騎馬犯邊塵。',64,'全唐诗/poet.song.84000.json','["疇昔江湖自在身，而今騎馬犯邊塵。", "寧無楚尾吳頭夢，歷遍燕南趙北春。", "壮士似渠終有遇，衰年如我尚誰親。", "屈州抑縣不伸里，老此嶔嶔可笑人。"]'),
('1dba901d-4c3f-49b4-871e-5c4ff50cb0a7','禹廟一首','劉一止','宋','宋诗','song-poetry','','[]','苗山風馭日翩翩，人道桐棺葬此嶺。',64,'全唐诗/poet.song.84000.json','["苗山風馭日翩翩，人道桐棺葬此嶺。", "今事獨聞鴉種麥，故村不見鳥耘田。", "遠憂邊塞清無日，更望倉箱屢有年。", "收攬封疆歸禹貢，忍看兵氣污山川。"]'),
('7c89fbc3-d448-47bb-a119-7679ba07f518','謝會稽守翟內相臨學行鄉飲酒之禮','劉一止','宋','宋诗','song-poetry','','[]','清曉傳呼振戟衣，泮林雲日炫旌旗。',64,'全唐诗/poet.song.84000.json','["清曉傳呼振戟衣，泮林雲日炫旌旗。", "風塵貼妥投戈後，色笑雍容勸學時。", "先世流芳今有繼，聖衷圖舊正疇咨。", "王褒願草得賢頌，可但中和宣布詩。"]'),
('984b277b-e329-49b6-a994-ef00fc0e673f','次韻方允迪秘監會稽相遇懷吳興舊遊二首  其一','劉一止','宋','宋诗','song-poetry','','[]','故山疇昔奉英遊，老去功名失路頭。',64,'全唐诗/poet.song.84000.json','["故山疇昔奉英遊，老去功名失路頭。", "江海一官如許冷，田園三載不知秋。", "謝公塘外千峰紫，何楷廬邊一径幽。", "心折少陵存殁句，恨無酒力破勞愁。"]'),
('1ad533da-ce59-4a2d-84f3-03880289062b','次韻方允迪秘監會稽相遇懷吳興舊遊二首  其二','劉一止','宋','宋诗','song-poetry','','[]','鑒湖列嶂自天開，雲色嵐光入酒杯。',64,'全唐诗/poet.song.84000.json','["鑒湖列嶂自天開，雲色嵐光入酒杯。", "忽遣同遊有陶謝，故應交契擬陳雷。", "他鄉日日典衣醉，公事時時牽馬來。", "要買扁舟窮勝絕，共追樵径晚風回。"]'),
('348f159b-dba2-48f3-acf5-f54fb2df367e','攜家從允迪借居鸕鷀源上沈必先侍御有詩寵其行次韻并呈二公二首  其一','劉一止','宋','宋诗','song-poetry','','[]','飄零暮景今如許，慚愧高人久卧廬。',64,'全唐诗/poet.song.84000.json','["飄零暮景今如許，慚愧高人久卧廬。", "好客兒童總歡喜，多情草木自扶疏。", "百年夢幻真何有，一壑風烟尚借居。", "寄謝南臺溫御史，此身休戚正關渠。"]'),
('915da620-8186-44e9-b96b-4e3a60d2cdeb','攜家從允迪借居鸕鷀源上沈必先侍御有詩寵其行次韻并呈二公二首  其二','劉一止','宋','宋诗','song-poetry','','[]','向來多病更多憂，命與誰謀出怨仇。',64,'全唐诗/poet.song.84000.json','["向來多病更多憂，命與誰謀出怨仇。", "坐念甘泉方避暑，不知楚澤又悲秋。", "長蛇肆毒心猶在，戰馬何時鞚暫休。", "横榻故人身衛主，素書能不復譏儂。"]'),
('d1ed2b69-f030-4415-8a0b-0bc4d9ff2966','再用韻呈允迪秘監江子我郎中二首  其一','劉一止','宋','宋诗','song-poetry','','[]','二紀風埃長作客，了知身世是蘧廬。',64,'全唐诗/poet.song.84000.json','["二紀風埃長作客，了知身世是蘧廬。", "老來詩酒都無味，亂後交親未肯疏。", "曾見雄風追楚賦，尚堪雌霓讀郊居。", "願公先卜嵌巖隱，秦利寧忘鄭國渠。"]'),
('9e4ba7ef-8e35-43a9-8322-81316367cd8e','再用韻呈允迪秘監江子我郎中二首  其二','劉一止','宋','宋诗','song-poetry','','[]','異時畎畝不忘憂，避俗今猶若避仇。',64,'全唐诗/poet.song.84000.json','["異時畎畝不忘憂，避俗今猶若避仇。", "直指威聲曾震嶽，封章義氣欲橫秋。", "詩成故客知無敵，酒盡憑誰爲起謀。", "歲晚相逢山在眼，從公腳歷頗能不。"]'),
('62fa9a21-cb10-4d28-b24f-5b8b57fea08d','次韻必先侍御和鄭維心憶梅並寄維心','劉一止','宋','宋诗','song-poetry','','[]','紫梅溪上春先到，餘不沙邊草未芳。',64,'全唐诗/poet.song.84000.json','["紫梅溪上春先到，餘不沙邊草未芳。", "五字真曾賦桑落，四弦猶憶調楓香。", "雪中孤艷應愁絕，竹外斜枝不掩藏。", "永望佳人在空谷，此時幽獨未須傷。"]'),
('fe51de96-64e0-4506-9250-0b5551910827','再用韻寄沈次律學士','劉一止','宋','宋诗','song-poetry','','[]','溪上青雲覆短牆，杖藜誰共掇幽芳。',64,'全唐诗/poet.song.84000.json','["溪上青雲覆短牆，杖藜誰共掇幽芳。", "忽驚候館梅花破，想見山齋竹葉香。", "倦客鬢絲今點染，使君心事獨韜藏。", "何當歸赴春盤約，苦苣嘉蔬未足傷。"]'),
('bd341989-1129-456a-a450-0ff8cc4ecf4c','次韻維心賦次律見一亭二首  其一','劉一止','宋','宋诗','song-poetry','','[]','向來金埓與銅山，可是無田未得閑。',64,'全唐诗/poet.song.84000.json','["向來金埓與銅山，可是無田未得閑。", "紙上功名追逸景，鏡中心事迫摧顔。", "溪雲慣作多時別，隴月今迎一箇還。", "始信柯田梨棗地，不令榛棘有遺删。"]'),
('9ed16851-fb4b-4870-b1b4-10d284694413','次韻維心賦次律見一亭二首  其二','劉一止','宋','宋诗','song-poetry','','[]','循除春水漸淙淙，心静魔軍久已降。',64,'全唐诗/poet.song.84000.json','["循除春水漸淙淙，心静魔軍久已降。", "未省芳菲誰是伴，不妨鸚燕自成雙。", "眼中濁酒傾如海，門外清溪欲擬江。", "會見扶藜添一老，共聽疏竹響風窗。"]'),
('9684ee54-96cc-48ee-9582-4e0e09ff1551','次韻維心赴次律賞芍藥一首','劉一止','宋','宋诗','song-poetry','','[]','巖前紅藥媚深幽，更爲餘春一笑留。',64,'全唐诗/poet.song.84000.json','["巖前紅藥媚深幽，更爲餘春一笑留。", "疇昔鄒枚俱倦客，而今陶謝得同遊。", "真香雨裛來無盡，妝艷風熏喜欲浮。", "未羡木奴千戶比，主人原是醉鄉侯。"]'),
('b2ff8635-7a08-4303-9863-f0576e794699','次韻維心贈葛魯卿待制求花栽一首','劉一止','宋','宋诗','song-poetry','','[]','此日寧無健步移，春前行近着花時。',64,'全唐诗/poet.song.84000.json','["此日寧無健步移，春前行近着花時。", "故園樂地今餘幾，小縣風光客不知。", "剩買名裁令亂眼，却嫌芳思只撩詩。", "屬公歸賦丹青手，問圃尋農獨我宜。"]'),
('9db0b719-554f-46ca-a4d7-8dd114130819','盧叔才相過夜話戲成一首','劉一止','宋','宋诗','song-poetry','','[]','七年詩酒恨難同，未省相看作麽容。',64,'全唐诗/poet.song.84000.json','["七年詩酒恨難同，未省相看作麽容。", "多病襄陽長瑟縮，古心冬夜更龍鍾。", "已知昔者非今者，莫問渠儂勝我儂。", "手剪西窗深夜燭，細聽吳語話心胸。"]'),
('fec4abf8-47e4-42be-ba47-8fec4d412668','寄雲門長老持公一首','劉一止','宋','宋诗','song-poetry','','[]','夢境清遊記昔曾，而今雙鬢已鬅鬙。',64,'全唐诗/poet.song.84000.json','["夢境清遊記昔曾，而今雙鬢已鬅鬙。", "此生有分尋雲水，到處逢人說葛藤。", "紫芋波稜真在眼，青鞋布韈未輸僧。", "會投枯木堂中老，只恐詩情罷不能。"]'),
('7353644e-a913-4c2f-8c3b-78cc572ccd37','次韻宋希仲貽故人虞仲容一首','劉一止','宋','宋诗','song-poetry','','[]','亂前交舊今餘幾，道故傷時得涕零。',64,'全唐诗/poet.song.84000.json','["亂前交舊今餘幾，道故傷時得涕零。", "門外溪山無賴碧，眼中鬚鬢可憐青。", "十年持槖氣横出，三斗朝天心獨醒。", "却喜元龍豪放在，不妨下馬索銀瓶。"]'),
('04590b9f-d180-4856-b953-824fb5ed8367','送希仲出守三衢一首','劉一止','宋','宋诗','song-poetry','','[]','臨別溪山眼重開，秋風揚旆更悠哉。',64,'全唐诗/poet.song.84000.json','["臨別溪山眼重開，秋風揚旆更悠哉。", "平生氣概今逾壯，一郡清平欲挽回。", "喪亂有誰談舊事，論思此日要真才。", "公行勿亟朝天路，帝有甘泉密詔來。"]'),
('5a6bcca9-3d09-4ffa-9cb0-1f11d885c0a1','次韻寄懷王元渤舍人一首','劉一止','宋','宋诗','song-poetry','','[]','倦飛鸞省戢脩翎，乞與雲山作卧屏。',64,'全唐诗/poet.song.84000.json','["倦飛鸞省戢脩翎，乞與雲山作卧屏。", "醉裏書床堆束筍，夢餘楸局見稀星。", "君心儻似當時赤，吾髪應無耐久青。", "老手尚堪驅使在，會持歸檝到溪亭。"]'),
('e6287cdb-136b-4403-b8ec-c44d4c5e32c8','林懿成檢正見貽次韻謝之林乃同年','劉一止','宋','宋诗','song-poetry','','[]','集英唱第偶追攀，老着青衫獨汗顔。',64,'全唐诗/poet.song.84000.json','["集英唱第偶追攀，老着青衫獨汗顔。", "富貴逼公那得謝，雲泉招我久應閑。", "鸞臺看展經綸手，鼇禁行趨供奉班。", "黄髮故人空跂想，應無春夢到林間。"]'),
('c2f5b1e7-6f5a-4be7-91e7-93b80359f8c3','将如會稽用允迪韻留別子我諸公一首','劉一止','宋','宋诗','song-poetry','','[]','對酒休悲落木秋，霜花猶足當傳籌。',64,'全唐诗/poet.song.84000.json','["對酒休悲落木秋，霜花猶足當傳籌。", "每憐別賦空多感，晚信離騷併是憂。", "盞底聖賢何足論，眼中涇渭正爭流。", "時危忍袖經綸手，行見聘書如鶴頭。"]'),
('f1827e0f-b4a3-4e37-9857-bcca125535ab','送方務德提幹赴官浙西一首','劉一止','宋','宋诗','song-poetry','','[]','二十年前湖海舊，而今人物粲琅玕。',64,'全唐诗/poet.song.84000.json','["二十年前湖海舊，而今人物粲琅玕。", "文章自襲家風美，骨相仍無父客寒。", "會有忠誠能貫日，不應漫浪懶爲官。", "他年鵷鷺行中見，儻似鸕鷀谷裏看。"]'),
('3a579f4e-1d34-4e15-8352-1b4bb8312d1f','次韻沈必先尚書見別一首','劉一止','宋','宋诗','song-poetry','','[]','翩翩旗尾破新晴，頗似龍駒脫在坰。',64,'全唐诗/poet.song.84000.json','["翩翩旗尾破新晴，頗似龍駒脫在坰。", "再上封章辭雨露，故令高節煥丹青。", "卿雲媚日懷仙隱，白鷺迎舟宿晚汀。", "預想山齋春酒熟，可無殘夢到南屏。"]'),
('b2e73377-2aa3-4681-b419-43d8be13673b','次韻傅子駿右司見貽一首','劉一止','宋','宋诗','song-poetry','','[]','大旆華鑣晝掩扉，松門沙步带山圍。',64,'全唐诗/poet.song.84000.json','["大旆華鑣晝掩扉，松門沙步带山圍。", "循除漲水春來急，釋嶠孤雲懶後歸。", "試看青鞋緣磴道，不妨野服坐苔磯。", "應嗟客路風塵暗，遶樹驚烏未得依。"]'),
('745391ad-92a9-42d7-a4de-0fc444a4eb39','次韻無言兄卜築二首  其一','劉一止','宋','宋诗','song-poetry','','[]','求田問舍豈徒爲，晚悟前言不我欺。',64,'全唐诗/poet.song.84000.json','["求田問舍豈徒爲，晚悟前言不我欺。", "地占玉杯初應卜，門臨苕水宛分枝。", "鄉關怪客歸何早，聖主思賢降不遲。", "磊落胸中三萬字，不應無意拯時危。"]'),
('fd08e8a4-7b0f-481c-8bf6-9ac24547ff2e','次韻無言兄卜築二首  其二','劉一止','宋','宋诗','song-poetry','','[]','石枕方床綠浪籐，清談散带似懷冰。',64,'全唐诗/poet.song.84000.json','["石枕方床綠浪籐，清談散带似懷冰。", "蔬盤尚雜水中蟹，羽翣莫揮瓜上蠅。", "五斗爲貧真世業，一廛歸隱豈人能。", "冥鴻萬里今何慕，應笑饑飛側翅鷹。"]'),
('93607fec-3f9f-4a46-9e28-6e6099b56c97','張仲宗判監別近三十年經由餘不訪余有詩次其韻','劉一止','宋','宋诗','song-poetry','','[]','亂前猶省當時事，亂後渾如隔世人。',64,'全唐诗/poet.song.84000.json','["亂前猶省當時事，亂後渾如隔世人。", "得見昇平且歡喜，莫将心念到亨屯。", "銜杯倘辦中山醉，覓句誰如小庾新。", "三十年前癡半黠，相逢終不忘天津。"]'),
('2edc770f-1715-49a1-9025-5d3dab0c0288','次韻沈次律家並蒂芍藥一首','劉一止','宋','宋诗','song-poetry','','[]','習家池館酒如淮，爲破幽人一日齋。',64,'全唐诗/poet.song.84000.json','["習家池館酒如淮，爲破幽人一日齋。", "前廡芳菲駢蒂萼，後堂鶯燕嘯朋儕。", "忽驚暗綠将成幄，却喜雙紅欲綴釵。", "草木會爲門戶慶，而今蘭玉已當階。"]'),
('737e44b7-8b6e-4a50-bf01-e5c9a99d59cb','次韻牧菴禪師持公見貽一首','劉一止','宋','宋诗','song-poetry','','[]','衲底摩尼直萬金，半生空探九淵尋。',64,'全唐诗/poet.song.84000.json','["衲底摩尼直萬金，半生空探九淵尋。", "波離懺罪何名罪，老可安心不見心。", "碧澗寒泉流自古，齋廚煮菜味常今。", "牧菴已斷人牛跡，純白何妨黑半侵。"]'),
('f2d6e223-2f62-4275-92b8-b395c828ed64','次韻鄭禹功見貽一首','劉一止','宋','宋诗','song-poetry','','[]','當年負笈京華客，振臂論交法從班。',64,'全唐诗/poet.song.84000.json','["當年負笈京華客，振臂論交法從班。", "何武誦詩來蜀郡，士龍持論出雲間。", "杯觴引滿風流甚，歲月驚心昨夢還。", "短檝未妨相訪覓，要看拄頰面西山。"]'),
('97eb412c-a140-4bae-8c65-3b83aeb42680','次韻徐季山學正釋奠先聖之作','劉一止','宋','宋诗','song-poetry','','[]','闕里躬祠通古昔，昇平禮樂信光明。',64,'全唐诗/poet.song.84000.json','["闕里躬祠通古昔，昇平禮樂信光明。", "威儀復見周多士，迂鄙何求漢兩生。", "佩委霜侵裳繡冷，庠開風振戟衣鳴。", "使君肅穆神心格，更看雍容佐國衡。"]'),
('aef88f69-a5e0-44ff-9ad1-51f8046fdfa5','次韻吳興守到官見貽一首','劉一止','宋','宋诗','song-poetry','','[]','步武初辭玉筍中，旌麾疑是到珠宮。',64,'全唐诗/poet.song.84000.json','["步武初辭玉筍中，旌麾疑是到珠宮。", "窗間巖岫如爭入，筆下雲烟洗不空。", "千里喜深車後雨，一堂仁浹扇時風。", "賓筵浪許陪真賞，底用蹣跚一秃翁。"]'),
('47ca6f2c-a0fc-4125-bc52-fea1b833be97','次韻吳興守雨中即事一首','劉一止','宋','宋诗','song-poetry','','[]','雨檻風簷欲墊巾，護花常恐減青春。',64,'全唐诗/poet.song.84000.json','["雨檻風簷欲墊巾，護花常恐減青春。", "融怡已復生頩頰，料峭真應恕老人。", "睡鴨吹香空結戀，遠峰攢碧似凝顰。", "野棠泪濕愁如許，半面徐妃不受勻。"]'),
('a99f438a-bf69-490f-af3e-2d0fdc11e478','次韻春日書懷二首  其一','劉一止','宋','宋诗','song-poetry','','[]','居士而今有底忙，生涯草草度年芳。',64,'全唐诗/poet.song.84000.json','["居士而今有底忙，生涯草草度年芳。", "平林漸見蔫紅委，野店初開煮酒香。", "尚有佳人來得得，不甘春事去堂堂。", "勝遊早晚追千騎，更看揮戈駐日光。"]'),
('cb1af7d7-380f-4365-9915-94241e000546','次韻春日書懷二首  其二','劉一止','宋','宋诗','song-poetry','','[]','水面紅雲次第鋪，東君未肯向人疏。',64,'全唐诗/poet.song.84000.json','["水面紅雲次第鋪，東君未肯向人疏。", "興高碧嶂千尋外，春在黄堂一笑餘。", "只怕玉醅浮盞斝，不嫌花片落襟裾。", "公歸行侍甘泉宴，留得新詩錦不如。"]'),
('f988cd29-bb8b-4274-b4ac-564c38396bbc','次韻吳興紀事一首','劉一止','宋','宋诗','song-poetry','','[]','懷紱初辭玉帝宮，白蘋洲在亂雲中。',64,'全唐诗/poet.song.84000.json','["懷紱初辭玉帝宮，白蘋洲在亂雲中。", "勸耕漢守宣恩詔，賣劍吳儂襲古風。", "花好未應慚洛浦，酒香何羡過新豐。", "他年圖畫賓筵勝，錦瑟傍邊有病翁。"]'),
('a7a8ad1b-903d-4e0d-9e55-3677cb9827fd','次韻九日四首  其一','劉一止','宋','宋诗','song-poetry','','[]','九日佳名今古重，鳳城秋色正明樓。',64,'全唐诗/poet.song.84000.json','["九日佳名今古重，鳳城秋色正明樓。", "廚供清釀香浮袂，恩賜黄花憶滿頭。", "千里風煙殊未惡，五亭吟嘯不應休。", "明年歸覲酬前賞，倘念衰翁尚四愁。"]'),
('9b6e9097-b438-47bc-a7bd-fa48c9fb0590','次韻九日四首  其二','劉一止','宋','宋诗','song-poetry','','[]','懷紱欣臨柳惲州，據床寧羡庾公樓。',64,'全唐诗/poet.song.84000.json','["懷紱欣臨柳惲州，據床寧羡庾公樓。", "雲横浦溆無重數，花遶巖巒最上頭。", "詩遣羊何聊共和，語驚陶謝未知休。", "自緣風物撩人意，不爲閑情作許愁。"]'),
('7985f3cd-4e14-489b-8294-81b4440f6184','次韻九日四首  其三','劉一止','宋','宋诗','song-poetry','','[]','蒲團趺坐冷知秋，笳鼓聲傳出郡樓。',64,'全唐诗/poet.song.84000.json','["蒲團趺坐冷知秋，笳鼓聲傳出郡樓。", "閱世夢中知是夢，說禪頭上更安頭。", "邦君化得俱吟詠，居士年應賦莫休。", "只恐官梅能動興，從梁江草喚人愁。"]'),
('34f20a16-31a8-46e7-88cf-3b6a6efc9d5d','次韻九日四首  其四','劉一止','宋','宋诗','song-poetry','','[]','向來風韻照清秋，氣壓元龍百尺樓。',64,'全唐诗/poet.song.84000.json','["向來風韻照清秋，氣壓元龍百尺樓。", "倒載時時憶池上，朝回日日醉江頭。", "甘泉正念論思舊，輔郡仍推譽望休。", "勃窣媻姗老歸客，賴公與酒得澆愁。"]'),
('523d2478-d5ec-47a3-af52-9d2ec1366ab4','次韻雪中聽琵琶一首','劉一止','宋','宋诗','song-poetry','','[]','燕堂曾許陪真賞，似識唐昌一樹花。',64,'全唐诗/poet.song.84000.json','["燕堂曾許陪真賞，似識唐昌一樹花。", "鶴骨松聲公耐雪，龜膓蟬腹我羞茶。", "星弰萬點疏還密，月帔千尋整復斜。", "要趁回風看舞態，莫令矯恨入琵琶。"]'),
('75647daf-575a-4850-87d2-ae46fce6902c','題毗山吳約仲曠遠亭一首','劉一止','宋','宋诗','song-poetry','','[]','追思五十年前夢，山壓平湖水次門。',64,'全唐诗/poet.song.84000.json','["追思五十年前夢，山壓平湖水次門。", "白鷺未慚公子貴，青松不屈大夫尊。", "文辭樸凸推鼻祖，標置孤高到耳孫。", "更喜新亭名意好，吳郎清峻芮郎温。"]'),
('ac3dbc83-71dc-4256-9217-a3428c147e9a','冬至汴下早行有感一首','劉一止','宋','宋诗','song-poetry','','[]','刺促驚時節，侵尋念物華。',48,'全唐诗/poet.song.84000.json','["刺促驚時節，侵尋念物華。", "半生多客裏，今日又天涯。", "曉月看眉嫵，飛雲亂眼花。", "窮途随物感，不必是思家。"]'),
('2619447e-eb86-4118-87e9-06a494dcde2b','和族兄無言題能仁寺當雲軒一首','劉一止','宋','宋诗','song-poetry','','[]','綠樹新迴合，斜窗舊邃深。',48,'全唐诗/poet.song.84000.json','["綠樹新迴合，斜窗舊邃深。", "壺觴如栗里，歲月似山陰。", "半世懷清隱，何年得此心。", "借床眠不熟，酒力横相侵。"]'),
('4cc4ec62-b375-47c9-ad48-386d721e1ef3','次韻袁審淵道舊思歸四首  其一','劉一止','宋','宋诗','song-poetry','','[]','寂寞襄陽老，南山憶弊廬。',48,'全唐诗/poet.song.84000.json','["寂寞襄陽老，南山憶弊廬。", "病來惟喜酒，歎罷每捐書。", "道路風塵暗，關河信息疏。", "逢人說沙漠，不忍問何如。"]'),
('2f8568f0-e156-45f5-a419-4c3403729caf','次韻袁審淵道舊思歸四首  其二','劉一止','宋','宋诗','song-poetry','','[]','十載溪亭舊，揮毫見古風。',48,'全唐诗/poet.song.84000.json','["十載溪亭舊，揮毫見古風。", "相如今病渴，東野尚鳴窮。", "眼界便鄉物，風流憶乃翁。", "一枰如夢斷，歸思渺千峰。"]'),
('53ccde7d-2ad8-47e3-843b-04fe5db6971a','次韻袁審淵道舊思歸四首  其三','劉一止','宋','宋诗','song-poetry','','[]','城郭如村步，官身等俗閑。',48,'全唐诗/poet.song.84000.json','["城郭如村步，官身等俗閑。", "對棋論小墅，拄頰望西山。", "異縣故交重，閑心幽事關。", "猶餘少年意，不計晚途艱。"]'),
('4954fddc-bb53-45ab-b731-c3bc91daf1f7','次韻袁審淵道舊思歸四首  其四','劉一止','宋','宋诗','song-poetry','','[]','虞氏隋唐後，當時尺五天。',48,'全唐诗/poet.song.84000.json','["虞氏隋唐後，當時尺五天。", "風煙鼻祖宅，翰墨耳孫賢。", "筇屐容相躡，杯觴得共傳。", "濟時吾老矣，看着祖生鞭。"]'),
('9937ff9b-47b2-41aa-ba69-14a0cd4693b8','次韻江子我雪句一首','劉一止','宋','宋诗','song-poetry','','[]','頭白高山早，千林一夜花。',48,'全唐诗/poet.song.84000.json','["頭白高山早，千林一夜花。", "雲深烏鬼嶼，風亂白鷗沙。", "刺促傷時事，飄零念歲華。", "天今洗兵馬，勿復問浮槎。"]'),
('c3a9397d-d58f-41c5-9926-d0140d3e88b0','梅山一首','劉一止','宋','宋诗','song-poetry','','[]','伊昔市門隱，山今尚姓梅。',48,'全唐诗/poet.song.84000.json','["伊昔市門隱，山今尚姓梅。", "危言關社稷，仙迹混蒿萊。", "此事誰云者，斯人安在哉。", "傷今更懷古，老意獨悲哀。"]'),
('f865e25f-7a29-42af-8ee3-64c355e2b2b5','送太學舊同舍及第歸鄉一首','劉一止','宋','宋诗','song-poetry','','[]','輦轂當年別，簪裳末路同。',48,'全唐诗/poet.song.84000.json','["輦轂當年別，簪裳末路同。", "江湖人已老，家國恨何窮。", "山有傷心碧，塵無沒馬紅。", "舉鞭還送客，落日泪痕中。"]'),
('a5dae15b-b577-4ad7-a8a1-0552b9ea4a32','次韻子我得俸一首','劉一止','宋','宋诗','song-poetry','','[]','祠官資薄俸，肥遯要清貧。',48,'全唐诗/poet.song.84000.json','["祠官資薄俸，肥遯要清貧。", "載酒久無客，乞醯惟有鄰。", "廣文寧厭肉，方朔漫長身。", "莫遣陳萇到，先生甑尚塵。"]'),
('fbf831a8-1618-4e43-a562-b2363f8ccbbb','冥冥寒食雨','劉一止','宋','宋诗','song-poetry','','[]','冥冥寒食雨，客意向誰親。',48,'全唐诗/poet.song.84000.json','["冥冥寒食雨，客意向誰親。", "泉亂如爭壑，花寒欲傍人。", "生涯長刺促，老氣尚輪囷。", "不負年年債，清詩新送春。"]'),
('b3f9cd16-94d7-40b2-a50c-f560ffc3a264','風氣東南異','劉一止','宋','宋诗','song-poetry','','[]','風氣東南異，陰晴早晚間。',48,'全唐诗/poet.song.84000.json','["風氣東南異，陰晴早晚間。", "日光時透隙，雲影半遮山。", "掃逕殘紅盡，開窗綠蔭還。", "寄聲桑苧友，幽興合相關。"]'),
('f4f94cf3-504a-41a8-9a07-b4dfde179ae6','綠暗山前路','劉一止','宋','宋诗','song-poetry','','[]','綠暗山前路，柔桑宛宛垂。',48,'全唐诗/poet.song.84000.json','["綠暗山前路，柔桑宛宛垂。", "稻秧分隴後，蠺繭下山時。", "白日繅車急，中宵織婦悲。", "老年官賦了，不長一絇絲。"]'),
('b5f1fe5d-a074-4fb6-9926-ebc2a0d40c9d','即事一首','劉一止','宋','宋诗','song-poetry','','[]','何物當門戶，青松及我長。',48,'全唐诗/poet.song.84000.json','["何物當門戶，青松及我長。", "佳山忘歲月，同汝過風霜。", "北澗花應盡，南榮草欲芳。", "病來歡意少，一醉未全忘。"]'),
('519bd4fe-2b61-4642-8d28-f957d8423c71','覽鏡一首','劉一止','宋','宋诗','song-poetry','','[]','契闊三年夢，飄零一寸心。',48,'全唐诗/poet.song.84000.json','["契闊三年夢，飄零一寸心。", "青青今變雪，種種僅齊簪。", "覽鏡渾相似，彈冠各不任。", "論交如許酒，情寄一杯深。"]'),
('ec03bbc9-4940-4d32-b970-38314808d78e','居士竂一首','劉一止','宋','宋诗','song-poetry','','[]','龍鍾居士相，落魄宰官身。',48,'全唐诗/poet.song.84000.json','["龍鍾居士相，落魄宰官身。", "長史風吹帽，林宗雨墊巾。", "安心惟壁觀，乞米賴僧鄰。", "曾並鴛行立，當時夢不真。"]'),
('c93e4eaf-f840-4e45-b08c-7aa86c3f0b56','次韻朱賓老過我對月小酌一首','劉一止','宋','宋诗','song-poetry','','[]','老人論舊事，感慨思悠哉。',48,'全唐诗/poet.song.84000.json','["老人論舊事，感慨思悠哉。", "暗喜生眉宇，新凉入酒杯。", "竹風誰汝和，檐月要人陪。", "此客非凡客，斯時得得來。"]'),
('93f4442a-92d9-4a65-9d0d-5942ab6e853a','遣興一首','劉一止','宋','宋诗','song-poetry','','[]','杯案惟菘韭，何因老骨強。',48,'全唐诗/poet.song.84000.json','["杯案惟菘韭，何因老骨強。", "昨朝方住雪，今日又加霜。", "寂歷僧廊暮，支離野步芳。", "歲時渾不省，得酒是春陽。"]'),
('3ceab0ec-e0ef-4f35-8810-28c3af738ecc','次韻吳興守春日書懷一首','劉一止','宋','宋诗','song-poetry','','[]','百榼償春酒，人言有別腸。',48,'全唐诗/poet.song.84000.json','["百榼償春酒，人言有別腸。", "披風醒午醉，擷蘂眷餘芳。", "白日何曾短，游絲得許長。", "向來情浩蕩，今者夢微茫。"]'),
('4ff352a3-91a4-4806-9630-d7e4859e5657','送徐叔鎮知縣罷官赴調一首','劉一止','宋','宋诗','song-poetry','','[]','劇論追前輩，憂思獨在民。',48,'全唐诗/poet.song.84000.json','["劇論追前輩，憂思獨在民。", "雪霜吾歲晚，金玉子心真。", "曾見除書舊，行膺薦墨新。", "君王問田叔，長者更何人。"]'),
('6b7dac6b-0be1-419b-8946-dbc7b4c835ab','送鄒德章教授之官合淝二首  其一','劉一止','宋','宋诗','song-poetry','','[]','晚色溪亭路，風帆去莫遮。',48,'全唐诗/poet.song.84000.json','["晚色溪亭路，風帆去莫遮。", "交情寄桑落，離恨渺天涯。", "志行今誰及，聲名莫謾誇。", "淮人問規範，說似道鄉家。"]'),
('d5292649-58c0-4f37-af98-ff6a76c461f6','送鄒德章教授之官合淝二首  其二','劉一止','宋','宋诗','song-poetry','','[]','古寺疏鐘裏，因依孰並遊。',48,'全唐诗/poet.song.84000.json','["古寺疏鐘裏，因依孰並遊。", "歌行如短李，邂逅得髯鄒。", "皎月林塘夜，青霜雉免秋。", "從今兩相憶，一酌酹儂不。"]'),
('bed3a20e-9ce2-432a-8f3a-f551b6c12c18','次韻賓老過會稽訪余同遊禹廟龍瑞宮晚歸二首  其一','劉一止','宋','宋诗','song-poetry','','[]','十載江湖客，重來霜鬢侵。',48,'全唐诗/poet.song.84000.json','["十載江湖客，重來霜鬢侵。", "事如春晝夢，山似故人心。", "步屧攀嶃絕，移舟出窈深。", "他時林樾底，歸去話登臨。"]'),
('01f3d616-b863-4248-9961-2864ed4b048b','次韻賓老過會稽訪余同遊禹廟龍瑞宮晚歸二首  其二','劉一止','宋','宋诗','song-poetry','','[]','禹穴徴前史，龍門訪隱書。',48,'全唐诗/poet.song.84000.json','["禹穴徴前史，龍門訪隱書。", "相攜如故里，失喜問吾廬。", "此日登山屐，他年下澤車。", "端能從我老，騰踐未應虚。"]'),
('0d9758e1-a05d-4121-b8bc-197d3b79c661','曾宏父将赴官都城示詩次韻自述并贈其行','劉一止','宋','宋诗','song-poetry','','[]','庾信多哀思，年來方解愁。',144,'全唐诗/poet.song.84000.json','["庾信多哀思，年來方解愁。", "低徊甘吏役，骯髒豈人謀。", "儋石纔知飽，私田詎敢求。", "尚能吟玉案，未忍困牙籌。", "公子年方壮，才名惜甚休。", "聊持江氏筆，來賦謝公樓。", "慷慨思千里，翺翔近十洲。", "逢時寧有愧，閱世自多憂。", "客路塵沙暗，春風草木柔。", "公行欣入洛，我老謝封留。", "日月消書帙，江湖落釣舟。", "經綸公等事，此意莫悠悠。"]'),
('c3c3b09c-73e0-44c0-84d5-48fa2206f037','次韻江子我郎中社飲一首','劉一止','宋','宋诗','song-poetry','','[]','社醵遺風在，田家禮數饒。',192,'全唐诗/poet.song.84000.json','["社醵遺風在，田家禮數饒。", "玉人疑解意，孺子故來邀。", "禦寇驚先饋，庚桑懼見杓。", "習鄉俱尚齒，惇族悟疏苗。", "未見琱戈静，方欣玉燭調。", "山寒時作暝，火老不成歊。", "釃酒無留榼，蒸豚發堕樵。", "蠻謳聲带苦，村舞拍頻招。", "野性疏鐘鼎，官身脫市朝。", "形随石骨瘦，心與澗花彫。", "朔漠音塵斷，羶胡意氣驕。", "誰爲今定遠，空作老邊韶。", "枉矢知天變，雙桃驗服妖。", "獻書慚痛哭，避地獨無聊。", "復古周宣治，中興太白謡。", "明年及春社，愁鬢雪應消。"]'),
('cff197c4-8608-47a9-a236-2f6458c6db0f','次韻子我秋分一首','劉一止','宋','宋诗','song-poetry','','[]','山中秋已半，蓬蓽晏方開。',48,'全唐诗/poet.song.84000.json','["山中秋已半，蓬蓽晏方開。", "不聽夜蟲話，焉知節物來。", "紫珠猶卧穗，青蘂未浮杯。", "欲射繫書鴈，非關烹不才。"]'),
('b63b8aff-da32-4a8f-9ed7-a2f6d560e3ed','聞親征一首','劉一止','宋','宋诗','song-poetry','','[]','十萬貔貅同日出，君王英武古無雙。',32,'全唐诗/poet.song.84000.json','["十萬貔貅同日出，君王英武古無雙。", "而今将士爭豪甚，爲報胡兒莫覷江。"]'),
('ddf6e53a-e147-4d64-af3f-5f0916e78c1a','賊臣劉豫挟虜騎犯兩淮天子親總六師出征賊騎摧衂宵遁鑾輿既還效杜拾遺作歡喜口號十二首  其一','劉一止','宋','宋诗','song-poetry','','[]','祖宗先德後刑誅，八葉升平振古無。',32,'全唐诗/poet.song.84000.json','["祖宗先德後刑誅，八葉升平振古無。", "馴致小羌如許黠，五兵雖惨亦時須。"]'),
